import UIKit
import SafariServices

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return false
        }
        
        guard let host = components.host,
              let path = components.path,
              host.contains("myapp.com") else {
            return false
        }
        
        if path == "/reset-password" {
            guard let token = extractToken(from: components) else {
                return false
            }
            
            navigateToPasswordReset(with: token)
            return true
        }
        
        return false
    }
    
    private func extractToken(from components: URLComponents) -> String? {
        guard let queryItems = components.queryItems else { return nil }
        
        for item in queryItems {
            if item.name == "token" {
                return item.value?.removingPercentEncoding
            }
        }
        
        return nil
    }
    
    private func navigateToPasswordReset(with token: String) {
        guard !token.isEmpty else { return }
        
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first else { return }
            
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            guard let resetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController else { return }
            
            resetVC.resetToken = token
            resetVC.modalPresentationStyle = .fullScreen
            
            if let rootVC = window.rootViewController {
                rootVC.present(resetVC, animated: true)
            }
        }
    }
}

extension UIApplication {
    func handleUniversalLink(_ url: URL) -> Bool {
        return UniversalLinkHandler.shared.handleUniversalLink(url)
    }
}

